def max_rod_cutting_profit(prices, n):
    if n <= 0:
        return 0

    dp = [0] * (n + 1)

    for i in range(1, n + 1):
        max_val = 0
        for j in range(1, i + 1):
            # prices[j-1] represents the profit for a piece of length j.
            # We ensure j-1 is a valid index for prices, otherwise assume 0 profit.
            current_piece_profit = prices[j-1] if j-1 < len(prices) else 0
            max_val = max(max_val, current_piece_profit + dp[i - j])
        dp[i] = max_val

    return dp[n]
